import type {
  ReactNode,
  ChangeEvent,
  SelectHTMLAttributes,
  OptionHTMLAttributes,
  ReactElement,
  FunctionComponent,
} from 'react';
import type {
  FloatingMenuProps,
  FloatingMenuItemProps,
  FloatingMenuGroupProps,
} from '@andes/floating-menu';
import type { TagProps, TagCollapsedProps } from '@andes/tag';
import type { WithRef, XOR } from '@andes/common';

type LabelOrSrLabel =
  | {
      /**
       * Text to display as label. In type: `standalone` it will act as a fallback placeholder too.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
       */
      label: string;

      /**
       * Text label for screen readers.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
       */
      srLabel?: string;
    }
  | {
      /**
       * Text to display as label. In type: `standalone` it will act as a fallback placeholder too.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
       */
      label?: string;

      /**
       * Text label for screen readers.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
       */
      srLabel: string;
    };

type TagCollapsedRenderProps = Pick<
  TagCollapsedProps,
  'disabled' | 'id' | 'limit'
>;

type TagRenderProps = Pick<
  TagProps,
  'className' | 'disabled' | 'id' | 'label' | 'onClose' | 'size'
>;

type MultipleContentRenderProp = {
  getTagCollapsedProps: (
    currentDisplayValues: Array<string> | string,
  ) => TagCollapsedRenderProps;
  getTagProps: (displayValue: string, index: number) => TagRenderProps;
};

type DropdownSpecificProps = {
  /**
   * Defines what type of dropdown should be rendered.
   *
   * If the standalone variant is needed, using directly the component <DropdownStandalone> is suggested, type="standalone" prop will be deprecated in a future major version.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
   * @default 'standalone'
   */
  type?: 'form' | 'standalone';
};

type DropdownFormSpecificProps = {
  /**
   * Text to display as a helper, hint or error to the user.
   * Only available for type: `form`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  helper?: ReactNode;

  /**
   * Component modifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  modifier?: 'error' | 'readonly';

  /**
   * Text to display as placeholder at the initial state of Dropdown. Only available for type: 'form'.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  placeholder?: string;

  /**
   * Callback to render custom content within the trigger when the dropdown is set to multiple. It should return an element to render.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  renderMultipleTriggerContent?: (
    values: Array<string> | string,
    renderProps: MultipleContentRenderProp,
  ) => ReactElement;
};

type DropdownStandaloneSpecificProps = {
  /**
   * Defines the sizing of the dropdown trigger.
   * Only available for `DropdownStandalone`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  size?: 'large' | 'medium' | 'small';
};

type FloatingMenuInheritedProps = {
  /**
   * Whether the dropdown should allow unselect the current selected option. This is not valid for multiple.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   * @default false
   */
  allowUnselect?: FloatingMenuProps['allowUnselect'];

  /**
   * Whether the dropdown should be open or not by default. (uncontrolled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  defaultOpen?: FloatingMenuProps['defaultOpen'];

  /**
   * Default selected value for dropdown (uncontrolled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  defaultValue?: FloatingMenuProps['defaultValue'];

  /**
   * Dropdown menu max height. It can be used for large options amount.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  menuMaxHeight?: FloatingMenuProps['menuMaxHeight'];

  /**
   * Allows a multiple selection menu.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   * @default false
   */
  multiple?: FloatingMenuProps['multiple'];

  /**
   * Callback executed when an option is selected. When multiple is on, values will be an array.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  onChange?: FloatingMenuProps['onChange'];

  /**
   * Callback executed when the dropdown menu is closed.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  onClose?: FloatingMenuProps['onClose'];

  /**
   * Callback executed when the dropdown menu is open.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  onOpen?: FloatingMenuProps['onOpen'];

  /**
   * Whether the dropdown should be open or not (controlled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  open?: FloatingMenuProps['open'];

  /**
   * Whether the dropdown should show a searchbox to filter dropdown items.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   * @default false
   */
  search?: FloatingMenuProps['search'];

  /**
   * Current selected value for dropdown (controlled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
   */
  value?: FloatingMenuProps['value'];
};

type DropdownCommonProps = FloatingMenuInheritedProps &
  LabelOrSrLabel &
  WithRef<HTMLDivElement> & {
    /**
     * Custom content, should be one or a collection or a mix of `<DropdownGroup>` and `<DropdownItem>`.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
     */
    children: Array<ReactElement> | ReactElement;

    /**
     * Add custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
     */
    className?: string;

    /**
     * Whether the dropdown should be disabled.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
     * @default false
     */
    disabled?: boolean;

    /**
     * Unique identifier.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
     */
    id?: string;

    /**
     * Dropdown menu alignment. When multiple or search is on, it always be `bottom`.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
     * @default 'center'
     */
    menuAlignment?: 'bottom' | 'center';

    /**
     * Callback to render a custom content inside the trigger button. It should return an element to render.
     *
     * If using slots (children) in `DropdownItem`, note that the first parameter passed to this callback
     * will always be a string representing the item's value.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#props | Documentation}
     */
    renderCustomTrigger?: (
      actualContent: ReactNode,
      currentValues: Array<string> | string,
    ) => ReactNode;
  };

type DropdownGroupSpecificProps = FloatingMenuGroupProps & {
  /**
   * Custom content, should be one or a collection of `<DropdownItem>`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdowngroup-extends-floatingmenugroup-api | Documentation}
   */
  children: FloatingMenuGroupProps['children'];
};

type FloatingMenuItemInheritedProps = {
  /**
   * Custom content. Should only be used in specific cases where usage of `primary` and `secondary` props are not enough. (not recommended).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownitem-extends-floatingmenuitem-api | Documentation}
   */
  children?: FloatingMenuItemProps['children'];

  /**
   * Text to display as secondary title.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownitem-extends-floatingmenuitem-api | Documentation}
   */
  description?: FloatingMenuItemProps['description'];

  /**
   * Whether the item should be disabled.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownitem-extends-floatingmenuitem-api | Documentation}
   */
  disabled?: FloatingMenuItemProps['disabled'];

  /**
   * Text to display as tertiary wording.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownitem-extends-floatingmenuitem-api | Documentation}
   */
  rightContent?: FloatingMenuItemProps['rightContent'];

  /**
   * Text to display as primary title.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownitem-extends-floatingmenuitem-api | Documentation}
   */
  title?: FloatingMenuItemProps['title'];

  /**
   * The value of the item that will be passed when is selected. If null, primary will be the value.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownitem-extends-floatingmenuitem-api | Documentation}
   */
  value: FloatingMenuItemProps['value'];
};

type DropdownNativeSpecificProps = WithRef<HTMLDivElement> & {
  /**
   * Custom content, should be a `<DropdownNativeItem>` or a collection of `<DropdownNativeItem>`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  children: Array<ReactElement> | ReactElement;

  /**
   * Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  className?: string;

  /**
   * Text or number marked as default selected value for dropdown (uncontrolled behavior).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   * @default false
   */
  defaultValue?: number | string;

  /**
   * Whether the dropdown should be disabled.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  disabled?: boolean;

  /**
   * Text to display as a helper, hint or error to the user.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  helper?: ReactNode;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  id?: string;

  /**
   * Label associated to the select.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  label: string;

  /**
   * Component modifier.
   * Readonly is not currently implemented.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  modifier?: 'error' | 'readonly';

  /**
   * Action that performs when one item is selected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  onChange?: (
    event: ChangeEvent<HTMLSelectElement>,
    value: number | string,
  ) => void;

  /**
   * Text or number marked as selected value for dropdown (controlled behavior).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnative | Documentation}
   */
  value?: number | string;
};

type DropdownNativeItemSpecificProps = {
  /**
   * Whether the item should be disabled.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnativeitem | Documentation}
   * @default false
   */
  disabled?: boolean;

  /**
   * Whether the item should be selected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnativeitem | Documentation}
   * @default false
   */
  selected?: boolean;

  /**
   * Text to display as primary title.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnativeitem | Documentation}
   */
  title: string;

  /**
   * The value of the item that will be passed when is selected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdownnativeitem | Documentation}
   */
  value?: string;
};

type DropdownGroupProps = DropdownGroupSpecificProps &
  Omit<FloatingMenuGroupProps, 'children'>;

type DropdownStandaloneProps = DropdownCommonProps &
  DropdownStandaloneSpecificProps;

type DropdownProps = DropdownSpecificProps &
  XOR<DropdownStandaloneProps, DropdownFormProps>;

type DropdownFormProps = DropdownCommonProps & DropdownFormSpecificProps;

type DropdownItemProps = FloatingMenuItemInheritedProps &
  Omit<FloatingMenuItemProps, 'children' | 'disabled' | 'title' | 'value'>;

type DropdownNativeProps = DropdownNativeSpecificProps &
  Omit<
    SelectHTMLAttributes<HTMLSelectElement>,
    | 'children'
    | 'defaultValue'
    | 'disabled'
    | 'id'
    | 'label'
    | 'onChange'
    | 'value'
  >;

/**
 * Dropdown
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/843296-dropdown/b/26f535 | UI Specs}
 * @example
 * import { Dropdown, DropdownItem } from '@andes/dropdown';
 *
 * const MyComponent = () => (
 *    <Dropdown
 *      id="component-id"
 *      label="Ordenar por"
 *      onChange={onChangeHandler}
 *    >
 *      <DropdownItem value="min-price" title="Menor precio" />
 *      <DropdownItem value="max-price" title="Mayor precio" />
 *      <DropdownItem value="featured" title="Más relevantes" /
 *    </Dropdown>
 * );
 */
export const Dropdown: FunctionComponent<DropdownProps>;

/**
 * Dropdown Form
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/843296-dropdown/b/26f535 | UI Specs}
 * @example
 * import { DropdownForm, DropdownItem } from '@andes/dropdown';
 *
 * const MyComponent = () => (
 *    <DropdownForm
 *      id="component-id"
 *      label="País"
 *      placeholder="Selecciona tu país de residencia"
 *      helper="Helper text"
 *      defaultValue="argentina"
 *      onChange={onChangeHandler}
 *    >
 *      <DropdownItem value="argentina" title="Argentina" />
 *      <DropdownItem value="brazil" title="Brazil" />
 *      <DropdownItem value="uruguay" title="Uruguay" />
 *      <DropdownItem value="chile" title="Chile" />
 *   </DropdownForm>
 * );
 */
export const DropdownForm: FunctionComponent<DropdownFormProps>;

/**
 * Dropdown Standalone
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/843296-dropdown/b/26f535 | UI Specs}
 * @example
 * import { DropdownStandalone, DropdownItem } from '@andes/dropdown';
 *
 * const MyComponent = () => (
 *    <DropdownStandalone
 *      defaultOpen={false}
 *      id="dropdown-story-id"
 *      label="Dropdown label"
 *      onChange={onChangeHandler}
 *      onClose={onCloseHandler}
 *      onOpen={onOpenHandler}
 *      srLabel=""
 *    >
 *      <DropdownItem
 *        title="Primera opción"
 *        value="1"
 *      />
 *      <DropdownItem
 *        title="Segunda opción"
 *        value="2"
 *      />
 *      <DropdownItem
 *        title="Tercer opción"
 *        value="3"
 *      />
 *   </DropdownStandalone>
 * );
 */
export const DropdownStandalone: FunctionComponent<DropdownStandaloneProps>;

/**
 * DropdownGroup
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/843296-dropdown/b/26f535 | UI Specs}
 * @example
 * import { Dropdown, DropdownGroup, DropdownItem } from '@andes/dropdown';
 *
 * const MyComponent = () => (
 * <Dropdown
 *  id="dropdown-story-id"
 *  label="Dropdown with groups items"
 *  placeholder="Select an item from a group"
 *  helper="Groups example"
 *  menuMaxHeight={250}
 * >
 *  <DropdownGroup key="tarjetas-de-credito" label="Tarjetas de crédito">
 *    <DropdownItem key="visa" value="visa" title="Visa" />
 *    <DropdownItem key="mastercard" value="mastercard" title="Mastercard" />
 *    <DropdownItem key="amex" value="amex" title="American Express" />
 *  </DropdownGroup>
 *  <DropdownGroup key="efectivo" label="Efectivo en redes de pago">
 *    <DropdownItem key="rapipado" value="rapipado" title="RapiPago" />
 *    <DropdownItem key="pagofacil" value="pagofacil" title="PagoFacil" />
 *  </DropdownGroup>
 * </Dropdown>
 * );
 */
export const DropdownGroup: FunctionComponent<DropdownGroupProps>;

/**
 * Dropdown item
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/843296-dropdown/b/26f535 | UI Specs}
 * @example
 * import { Dropdown, DropdownItem } from '@andes/dropdown';
 *
 * const MyComponent = () => (
 *    <Dropdown
 *      id="component-id"
 *      label="País"
 *      placeholder="Selecciona tu país de residencia"
 *      helper="Helper text"
 *      defaultValue="argentina"
 *      onChange={onChangeHandler}
 *    >
 *      <DropdownItem value="argentina" title="Argentina" />
 *      <DropdownItem value="brazil" title="Brazil" />
 *      <DropdownItem value="uruguay" title="Uruguay" />
 *      <DropdownItem value="chile" title="Chile" />
 *   </Dropdown>
 * );
 */
export const DropdownItem: FunctionComponent<DropdownItemProps>;

/**
 * Dropdown Native
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/843296-dropdown/b/26f535 | UI Specs}
 * @example
 * import { DropdownNative, DropdownNativeItem } from '@andes/dropdown';
 *
 * const MyComponent = () => (
 *    <DropdownNative
 *      helper="Mensaje de ayuda"
 *      id="dropdown-native-id"
 *      label="Dropdown label"
 *      onChange={onChangeHandler}
 *    >
 *      <DropdownNativeItem
 *        title="Primera opción"
 *        value="1"
 *      />
 *      <DropdownNativeItem
 *        title="Segunda opción"
 *        value="2"
 *      />
 *    </DropdownNative>
 * );
 */
export const DropdownNative: FunctionComponent<DropdownNativeProps>;

/**
 * Dropdown Native Item
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/dropdown#dropdown | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/843296-dropdown/b/26f535 | UI Specs}
 * @example
 * import { DropdownNative, DropdownNativeItem } from '@andes/dropdown';
 *
 * const MyComponent = () => (
 *    <DropdownNative
 *      helper="Mensaje de ayuda"
 *      id="dropdown-native-id"
 *      label="Dropdown label"
 *      onChange={onChangeHandler}
 *    >
 *      <DropdownNativeItem
 *        title="Primera opción"
 *        value="1"
 *      />
 *      <DropdownNativeItem
 *        title="Segunda opción"
 *        value="2"
 *      />
 *    </DropdownNative>
 * );
 */
export const DropdownNativeItem: FunctionComponent<DropdownItemProps>;

export type DropdownNativeItemProps = DropdownNativeItemSpecificProps &
  Omit<
    OptionHTMLAttributes<HTMLOptionElement>,
    'disabled' | 'selected' | 'value'
  >;
